(window.webpackJsonp=window.webpackJsonp||[]).push([[669],{644:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">let</span> hash={}\\n<span class=\\"hljs-keyword\\">var</span> FindElements = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  hash={}\\n  root.val=<span class=\\"hljs-number\\">0</span>\\n  hash[<span class=\\"hljs-number\\">0</span>]=<span class=\\"hljs-literal\\">true</span>\\n  dfs(root)\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> val=root.val\\n    <span class=\\"hljs-keyword\\">if</span>(root.left){\\n      root.left.val=val*<span class=\\"hljs-number\\">2</span>+<span class=\\"hljs-number\\">1</span>\\n      hash[root.left.val]=<span class=\\"hljs-literal\\">true</span>\\n      dfs(root.left)\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(root.right){\\n      root.right.val=val*<span class=\\"hljs-number\\">2</span>+<span class=\\"hljs-number\\">2</span>\\n      hash[root.right.val]=<span class=\\"hljs-literal\\">true</span>\\n      dfs(root.right)\\n    }\\n  }\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} target\\n * @return {boolean}\\n */</span>\\nFindElements.prototype.find = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">target</span>) </span>{\\n    <span class=\\"hljs-keyword\\">return</span> !!hash[target]\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your FindElements object will be instantiated and called as such:\\n * var obj = new FindElements(root)\\n * var param_1 = obj.find(target)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"find-elements-in-a-contaminated-binary-tree","hasThinking":false,"content":"<p>\u7ed9\u51fa\u4e00\u4e2a\u6ee1\u8db3\u4e0b\u8ff0\u89c4\u5219\u7684\u4e8c\u53c9\u6811\uff1a</p>\\n\\n<ol>\\n\\t<li><code>root.val == 0</code></li>\\n\\t<li>\u5982\u679c <code>treeNode.val == x</code> \u4e14&nbsp;<code>treeNode.left != null</code>\uff0c\u90a3\u4e48&nbsp;<code>treeNode.left.val == 2 * x + 1</code></li>\\n\\t<li>\u5982\u679c <code>treeNode.val == x</code> \u4e14 <code>treeNode.right != null</code>\uff0c\u90a3\u4e48&nbsp;<code>treeNode.right.val == 2 * x + 2</code></li>\\n</ol>\\n\\n<p>\u73b0\u5728\u8fd9\u4e2a\u4e8c\u53c9\u6811\u53d7\u5230\u300c\u6c61\u67d3\u300d\uff0c\u6240\u6709\u7684&nbsp;<code>treeNode.val</code>&nbsp;\u90fd\u53d8\u6210\u4e86&nbsp;<code>-1</code>\u3002</p>\\n\\n<p>\u8bf7\u4f60\u5148\u8fd8\u539f\u4e8c\u53c9\u6811\uff0c\u7136\u540e\u5b9e\u73b0&nbsp;<code>FindElements</code>&nbsp;\u7c7b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>FindElements(TreeNode* root)</code>&nbsp;\u7528\u53d7\u6c61\u67d3\u7684\u4e8c\u53c9\u6811\u521d\u59cb\u5316\u5bf9\u8c61\uff0c\u4f60\u9700\u8981\u5148\u628a\u5b83\u8fd8\u539f\u3002</li>\\n\\t<li><code>bool find(int target)</code>&nbsp;\u5224\u65ad\u76ee\u6807\u503c&nbsp;<code>target</code>&nbsp;\u662f\u5426\u5b58\u5728\u4e8e\u8fd8\u539f\u540e\u7684\u4e8c\u53c9\u6811\u4e2d\u5e76\u8fd4\u56de\u7ed3\u679c\u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/16/untitled-diagram-4-1.jpg\\" style=\\"height: 119px; width: 320px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\n[&quot;FindElements&quot;,&quot;find&quot;,&quot;find&quot;]\\n[[[-1,null,-1]],[1],[2]]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,false,true]\\n<strong>\u89e3\u91ca\uff1a</strong>\\nFindElements findElements = new FindElements([-1,null,-1]); \\nfindElements.find(1); // return False \\nfindElements.find(2); // return True </pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/16/untitled-diagram-4.jpg\\" style=\\"height: 198px; width: 400px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\n[&quot;FindElements&quot;,&quot;find&quot;,&quot;find&quot;,&quot;find&quot;]\\n[[[-1,-1,-1,-1,-1]],[1],[3],[5]]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,true,true,false]\\n<strong>\u89e3\u91ca\uff1a</strong>\\nFindElements findElements = new FindElements([-1,-1,-1,-1,-1]);\\nfindElements.find(1); // return True\\nfindElements.find(3); // return True\\nfindElements.find(5); // return False</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/16/untitled-diagram-4-1-1.jpg\\" style=\\"height: 274px; width: 306px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>\\n[&quot;FindElements&quot;,&quot;find&quot;,&quot;find&quot;,&quot;find&quot;,&quot;find&quot;]\\n[[[-1,null,-1,-1,null,-1]],[2],[3],[4],[5]]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,true,false,false,true]\\n<strong>\u89e3\u91ca\uff1a</strong>\\nFindElements findElements = new FindElements([-1,null,-1,-1,null,-1]);\\nfindElements.find(2); // return True\\nfindElements.find(3); // return False\\nfindElements.find(4); // return False\\nfindElements.find(5); // return True\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>TreeNode.val == -1</code></li>\\n\\t<li>\u4e8c\u53c9\u6811\u7684\u9ad8\u5ea6\u4e0d\u8d85\u8fc7&nbsp;<code>20</code></li>\\n\\t<li>\u8282\u70b9\u7684\u603b\u6570\u5728&nbsp;<code>[1,&nbsp;10^4]</code>&nbsp;\u4e4b\u95f4</li>\\n\\t<li>\u8c03\u7528&nbsp;<code>find()</code>&nbsp;\u7684\u603b\u6b21\u6570\u5728&nbsp;<code>[1,&nbsp;10^4]</code>&nbsp;\u4e4b\u95f4</li>\\n\\t<li><code>0 &lt;= target &lt;= 10^6</code></li>\\n</ul>\\n","title":"1261. \u5728\u53d7\u6c61\u67d3\u7684\u4e8c\u53c9\u6811\u4e2d\u67e5\u627e\u5143\u7d20","relatedTags":["\u6811","\u54c8\u5e0c\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1261"}')}}]);